import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const TYPE_ICON  = { certificate:'📜', project:'💻', internship:'🏢', publication:'📄', award:'🏆', course:'📚', other:'⭐' };
const TYPE_COLOR = { certificate:'#6c63ff', project:'#00d4aa', internship:'#ffb347', publication:'#ff6b9d', award:'#ffd700', course:'#4ade80', other:'#9aa3bf' };

export default function StudentDashboard() {
  const { user, API } = useAuth();
  const navigate = useNavigate();
  const [projects, setProjects]         = useState([]);
  const [requests, setRequests]         = useState([]);
  const [achievements, setAchievements] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading]           = useState(true);

  useEffect(() => {
    const load = async () => {
      const token = localStorage.getItem('token');
      const h = { headers: { Authorization: `Bearer ${token}` }, timeout: 15000 };
      try {
        const [pRes, rRes, aRes, anRes] = await Promise.all([
          axios.get(`${API}/projects?status=open`, h),
          axios.get(`${API}/requests/my`, h),
          axios.get(`${API}/achievements/my`, h),
          axios.get(`${API}/announcements`, h),
        ]);
        setProjects(pRes.data);
        setRequests(rRes.data);
        setAchievements(aRes.data);
        setAnnouncements(anRes.data.slice(0, 3));
      } catch {}
      setLoading(false);
    };
    load();
  }, [API]);

  const calcMatch = (skills) => {
    if (!user.skills?.length || !skills?.length) return 0;
    const s = user.skills.map(x => x.toLowerCase());
    const r = skills.map(x => x.toLowerCase());
    const matched = r.filter(skill => s.some(ss => ss.includes(skill) || skill.includes(ss)));
    return Math.round((matched.length / r.length) * 100);
  };

  const appliedIds = new Set(requests.map(r => r.project?._id));
  const accepted   = requests.filter(r => r.status === 'accepted');
  const pending    = requests.filter(r => r.status === 'pending');
  const rejected   = requests.filter(r => r.status === 'rejected');

  // Sort projects by match score
  const recommended = [...projects]
    .map(p => ({ ...p, match: calcMatch(p.requiredSkills) }))
    .sort((a, b) => b.match - a.match)
    .slice(0, 4);

  const stats = [
    { label: 'Applied',    value: requests.length,   icon: '📬', color: '#6c63ff', link: '/requests' },
    { label: 'Accepted',   value: accepted.length,   icon: '✅', color: '#4ade80', link: '/requests' },
    { label: 'Pending',    value: pending.length,    icon: '⏳', color: '#ffb347', link: '/requests' },
    { label: 'Achievements', value: achievements.length, icon: '🏆', color: '#00d4aa', link: '/achievements' },
  ];

  const statusStyle = {
    accepted: { bg:'rgba(74,222,128,0.1)',  color:'#4ade80',  border:'#4ade8040',  label:'✅ Accepted'  },
    pending:  { bg:'rgba(255,179,71,0.1)',  color:'#ffb347',  border:'#ffb34740',  label:'⏳ Pending'   },
    rejected: { bg:'rgba(255,87,87,0.1)',   color:'#ff5757',  border:'#ff575740',  label:'❌ Rejected'  },
  };

  if (loading) return (
    <div style={{padding:'3rem',textAlign:'center'}}>
      <div style={{fontSize:'2rem',marginBottom:'1rem'}}>⏳</div>
      <div style={{color:'#6c63ff'}}>Loading your dashboard...</div>
    </div>
  );

  return (
    <div style={{padding:'2rem',maxWidth:1200,margin:'0 auto'}}>

      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'2rem',flexWrap:'wrap',gap:'1rem'}}>
        <div>
          <h1 style={{fontWeight:800,fontSize:'1.75rem',marginBottom:'0.25rem'}}>Welcome back, {user.name.split(' ')[0]} 👋</h1>
          <p style={{color:'#9aa3bf'}}>{user.department} · {user.year}</p>
        </div>
        <div style={{display:'flex',gap:'0.75rem'}}>
          <Link to="/projects" style={{padding:'10px 18px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,textDecoration:'none',fontSize:'0.875rem'}}>🔍 Browse Projects</Link>
          <Link to="/achievements" style={{padding:'10px 18px',background:'transparent',border:'1px solid #252d47',borderRadius:10,color:'#9aa3bf',fontWeight:600,textDecoration:'none',fontSize:'0.875rem'}}>🏆 Add Achievement</Link>
        </div>
      </div>

      {/* Stats — clickable */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'1rem',marginBottom:'2rem'}}>
        {stats.map((s, i) => (
          <div key={i} onClick={()=>navigate(s.link)} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',cursor:'pointer',transition:'border-color 0.2s'}}
            onMouseEnter={e=>e.currentTarget.style.borderColor=s.color+'60'}
            onMouseLeave={e=>e.currentTarget.style.borderColor='#252d47'}
          >
            <div style={{fontSize:'1.5rem',marginBottom:'0.5rem'}}>{s.icon}</div>
            <div style={{fontSize:'2rem',fontWeight:800,color:s.color}}>{s.value}</div>
            <div style={{color:'#9aa3bf',fontSize:'0.875rem',marginTop:'0.25rem'}}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Latest Announcements */}
      {announcements.length > 0 && (
        <div style={{marginBottom:'2rem'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'0.75rem'}}>
            <h2 style={{fontWeight:700,fontSize:'1.1rem'}}>📢 Latest Notices</h2>
            <Link to="/announcements" style={{color:'#6c63ff',fontSize:'0.875rem',fontWeight:600}}>View all →</Link>
          </div>
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:'0.75rem'}}>
            {announcements.map(a => (
              <div key={a._id} onClick={()=>navigate('/announcements')} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:12,padding:'1rem',cursor:'pointer'}}>
                <div style={{fontWeight:700,fontSize:'0.875rem',color:'#e8eaf0',marginBottom:'0.25rem'}}>{a.title}</div>
                <div style={{color:'#9aa3bf',fontSize:'0.78rem',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{a.content}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div style={{display:'grid',gridTemplateColumns:'2fr 1fr',gap:'2rem',marginBottom:'2rem'}}>

        {/* Recommended Projects */}
        <div>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
            <h2 style={{fontWeight:700,fontSize:'1.1rem'}}>🎯 Recommended Projects</h2>
            <Link to="/projects" style={{color:'#6c63ff',fontSize:'0.875rem',fontWeight:600}}>View all →</Link>
          </div>
          {recommended.length === 0 ? (
            <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'2rem',textAlign:'center',color:'#5c6580'}}>
              <div style={{fontSize:'2rem',marginBottom:'0.5rem'}}>📭</div>
              <div>No open projects yet</div>
            </div>
          ) : recommended.map(p => (
            <Link key={p._id} to={`/projects/${p._id}`} style={{textDecoration:'none'}}>
              <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',marginBottom:'0.75rem',cursor:'pointer',transition:'border-color 0.2s'}}
                onMouseEnter={e=>e.currentTarget.style.borderColor='#6c63ff40'}
                onMouseLeave={e=>e.currentTarget.style.borderColor='#252d47'}
              >
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'0.5rem'}}>
                  <h3 style={{fontWeight:700,fontSize:'0.95rem',color:'#e8eaf0',flex:1,marginRight:'0.75rem'}}>{p.title}</h3>
                  <div style={{display:'flex',gap:'0.4rem',flexShrink:0}}>
                    {appliedIds.has(p._id) && <span style={{background:'rgba(74,222,128,0.1)',color:'#4ade80',border:'1px solid #4ade8040',borderRadius:99,padding:'2px 8px',fontSize:'0.65rem',fontWeight:600}}>✓ Applied</span>}
                    <span style={{background:'rgba(0,212,170,0.1)',color:'#00d4aa',border:'1px solid #00d4aa40',borderRadius:99,padding:'2px 8px',fontSize:'0.65rem',fontWeight:600}}>Open</span>
                  </div>
                </div>
                <div style={{color:'#5c6580',fontSize:'0.8rem',marginBottom:'0.75rem'}}>{p.faculty?.name} · {p.faculty?.department}</div>

                {/* Match bar */}
                <div style={{marginBottom:'0.75rem'}}>
                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:'4px'}}>
                    <span style={{fontSize:'0.7rem',color:'#5c6580'}}>Skill Match</span>
                    <span style={{fontSize:'0.7rem',color: p.match>=70?'#4ade80':p.match>=40?'#ffb347':'#ff5757',fontWeight:700}}>{p.match}%</span>
                  </div>
                  <div style={{height:5,background:'#252d47',borderRadius:99,overflow:'hidden'}}>
                    <div style={{height:'100%',width:`${p.match}%`,background:p.match>=70?'#4ade80':p.match>=40?'#ffb347':'#ff5757',borderRadius:99,transition:'width 0.5s'}} />
                  </div>
                </div>

                <div style={{display:'flex',gap:'0.4rem',flexWrap:'wrap'}}>
                  {p.requiredSkills?.slice(0,4).map(s => (
                    <span key={s} style={{padding:'2px 8px',borderRadius:99,background:'rgba(108,99,255,0.1)',border:'1px solid #6c63ff30',color:'#9aa3bf',fontSize:'0.7rem'}}>{s}</span>
                  ))}
                </div>
              </div>
            </Link>
          ))}
        </div>

        {/* My Applications */}
        <div>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
            <h2 style={{fontWeight:700,fontSize:'1.1rem'}}>📬 My Applications</h2>
            <Link to="/requests" style={{color:'#6c63ff',fontSize:'0.875rem',fontWeight:600}}>View all →</Link>
          </div>

          {requests.length === 0 ? (
            <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'2rem',textAlign:'center',color:'#5c6580'}}>
              <div style={{fontSize:'2rem',marginBottom:'0.5rem'}}>📭</div>
              <div style={{fontSize:'0.875rem',marginBottom:'0.75rem'}}>No applications yet</div>
              <Link to="/projects" style={{padding:'8px 16px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',borderRadius:8,color:'#fff',fontSize:'0.8rem',fontWeight:700,textDecoration:'none'}}>Browse Projects</Link>
            </div>
          ) : (
            <>
              {/* Accepted projects — show prominently */}
              {accepted.length > 0 && (
                <div style={{background:'rgba(74,222,128,0.05)',border:'1px solid #4ade8030',borderRadius:14,padding:'1rem',marginBottom:'0.75rem'}}>
                  <div style={{color:'#4ade80',fontWeight:700,fontSize:'0.8rem',marginBottom:'0.5rem'}}>✅ ACCEPTED PROJECTS</div>
                  {accepted.map(r => (
                    <div key={r._id} onClick={()=>navigate(`/projects/${r.project?._id}`)} style={{cursor:'pointer',padding:'0.5rem 0',borderBottom:'1px solid #4ade8020'}}>
                      <div style={{fontWeight:600,fontSize:'0.875rem',color:'#e8eaf0'}}>{r.project?.title}</div>
                      <div style={{fontSize:'0.75rem',color:'#4ade80'}}>by {r.faculty?.name}</div>
                    </div>
                  ))}
                </div>
              )}

              {/* Other applications */}
              {[...pending, ...rejected].slice(0,4).map(r => {
                const ss = statusStyle[r.status] || statusStyle.pending;
                return (
                  <div key={r._id} onClick={()=>navigate(`/projects/${r.project?._id}`)} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:12,padding:'0.875rem',marginBottom:'0.5rem',cursor:'pointer'}}>
                    <div style={{fontWeight:600,fontSize:'0.875rem',color:'#e8eaf0',marginBottom:'0.2rem'}}>{r.project?.title}</div>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                      <div style={{fontSize:'0.75rem',color:'#9aa3bf'}}>{r.faculty?.name}</div>
                      <span style={{padding:'2px 8px',borderRadius:99,fontSize:'0.7rem',fontWeight:600,background:ss.bg,color:ss.color,border:`1px solid ${ss.border}`}}>{ss.label}</span>
                    </div>
                  </div>
                );
              })}
            </>
          )}
        </div>
      </div>

      {/* My Achievements */}
      <div>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
          <h2 style={{fontWeight:700,fontSize:'1.1rem'}}>🏆 My Achievements</h2>
          <Link to="/achievements" style={{color:'#6c63ff',fontSize:'0.875rem',fontWeight:600}}>
            {achievements.length === 0 ? '+ Add Achievement' : 'Manage →'}
          </Link>
        </div>
        {achievements.length === 0 ? (
          <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'2rem',textAlign:'center',color:'#5c6580'}}>
            <div style={{fontSize:'2rem',marginBottom:'0.5rem'}}>🏆</div>
            <div style={{fontSize:'0.875rem',marginBottom:'0.75rem'}}>No achievements added yet</div>
            <Link to="/achievements" style={{padding:'8px 20px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',borderRadius:8,color:'#fff',fontSize:'0.8rem',fontWeight:700,textDecoration:'none'}}>+ Add Certificate or Project</Link>
          </div>
        ) : (
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(250px,1fr))',gap:'1rem'}}>
            {achievements.slice(0,4).map(a => {
              const color = TYPE_COLOR[a.type] || '#9aa3bf';
              const icon  = TYPE_ICON[a.type]  || '⭐';
              return (
                <div key={a._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,overflow:'hidden'}}>
                  {a.imageBase64 && <div style={{height:90,overflow:'hidden'}}><img src={a.imageBase64} alt={a.title} style={{width:'100%',height:'100%',objectFit:'cover'}} /></div>}
                  <div style={{padding:'1rem'}}>
                    <span style={{padding:'2px 10px',borderRadius:99,fontSize:'0.7rem',fontWeight:700,background:`${color}15`,color,border:`1px solid ${color}30`}}>{icon} {a.type}</span>
                    <div style={{fontWeight:700,fontSize:'0.9rem',marginTop:'0.5rem',color:'#e8eaf0'}}>{a.title}</div>
                    {a.issuer && <div style={{color:'#9aa3bf',fontSize:'0.75rem'}}>{a.issuer}</div>}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
